// utils/telegram.browser.js
// WARNING: using bot token in client-side code is insecure and not recommended.
// Use only for quick demos/testing. For production, do requests from server.

const TELEGRAM_MAX = 4096;

/** splitText: разбивает текст на части <= max, стараясь резать по \n/пробелам */
function splitText(text, max = TELEGRAM_MAX) {
  if (text.length <= max) return [text];
  const parts = [];
  let start = 0;
  while (start < text.length) {
    if (text.length - start <= max) {
      parts.push(text.slice(start));
      break;
    }
    let end = start + max;
    let cut = text.lastIndexOf('\n', end);
    if (cut <= start) cut = text.lastIndexOf(' ', end);
    if (cut <= start) cut = end;
    parts.push(text.slice(start, cut));
    start = cut;
    while (start < text.length && (text[start] === '\n' || text[start] === ' ')) start++;
  }
  return parts;
}

/** sendSingle: отправляет одну часть через fetch, обрабатывает 429 retry_after */
async function sendSingle(token, chatId, body, retries = 5) {
  const url = `https://api.telegram.org/bot${encodeURIComponent(token)}/sendMessage`;
  try {
    const resp = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(Object.assign({ chat_id: chatId }, body)),
    });

    const json = await resp.json().catch(() => null);

    if (resp.status === 429 && retries > 0) {
      // Telegram возвращает parameters.retry_after (в секундах)
      let wait = 1;
      if (json && json.parameters && json.parameters.retry_after) {
        wait = Number(json.parameters.retry_after);
      } else {
        wait = Math.min(10, (6 - retries) * 2);
      }
      await new Promise(r => setTimeout(r, wait * 1000));
      return sendSingle(token, chatId, body, retries - 1);
    }

    if (!resp.ok || !json || !json.ok) {
      const msg = json && json.description ? json.description : `HTTP ${resp.status}`;
      const err = new Error(`Telegram API error: ${msg}`);
      err.response = json;
      throw err;
    }

    return json;
  } catch (err) {
    // пробрасываем дальше
    throw err;
  }
}

/**
 * default export
 * @param {string} token - бот токен (не храните в публичном клиенте!)
 * @param {string|number} chatId
 * @param {string} text
 * @param {object} [opts] дополнительные опции sendMessage
 * @returns {Promise<object[]>}
 */
export default async function sendMessage(token, chatId, text, opts = {}) {
  if (!token) throw new Error('Telegram bot token is required (but do NOT put it in production client)');
  if (!chatId) throw new Error('chatId is required');
  if (typeof text !== 'string') throw new Error('text must be a string');

  const parts = splitText(text, TELEGRAM_MAX);
  const results = [];

  for (let i = 0; i < parts.length; i++) {
    const body = Object.assign({ text: parts[i] }, opts);

    // Если используете MarkdownV2 / HTML — аккуратно с разбиением (возможны ошибки разметки).
    const res = await sendSingle(token, chatId, body);
    results.push(res);

    if (i !== parts.length - 1) {
      // короткая пауза, чтобы снизить риск rate limit
      await new Promise(r => setTimeout(r, 300));
    }
  }

  return results;
}
